/* Aurora Design System — component base styles.

   Every rule here lives in `@layer aurora-components`. Tailwind's `utilities`
   layer is ordered AFTER it (see app/globals.css), so utility classes win over
   these base rules — the shadcn-idiomatic override behavior.

   Replaces the old per-component runtime <style> injection (ensureCSS/injectOnce):
   that injected UNLAYERED CSS at runtime, which beat Tailwind utilities (cascade
   bug), was not SSR'd (FOUC), and tripped strict CSP. Build-time + layered + SSR'd
   fixes all three. Generated by scratchpad/assemble.mjs from per-component parts.
   The consuming app must declare the layer order:
     @layer theme, base, components, aurora-components, utilities; */

@layer aurora-components {
  /* ─── button ─── */
/* ─── button ──────────────────────────────────────────────────────────── */
  .aurora-btn {
    position: relative; display: inline-flex; align-items: center; justify-content: center; gap: 7px;
    white-space: nowrap; cursor: pointer; user-select: none; font-family: var(--font-sans, Inter, sans-serif);
    font-weight: 560; border: 1px solid var(--aurora-border-strong); background: var(--aurora-control-surface);
    color: var(--aurora-text-primary); height: 32px; padding: 0 14px; border-radius: 9px; font-size: 13px;
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.05), 0 1px 2px rgba(0,0,0,0.34), 0 2px 6px rgba(0,0,0,0.16); text-decoration: none; box-sizing: border-box;
    transition: background 150ms var(--motion-ease-out, ease), border-color 150ms var(--motion-ease-out, ease), box-shadow 200ms var(--motion-ease-out, ease), color 150ms var(--motion-ease-out, ease), transform 80ms ease-out;
  }
  .aurora-btn:active { transform: translateY(1px); }
  .aurora-btn:focus-visible { outline: none; box-shadow: inset 0 1px 0 rgba(255,255,255,0.055), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 45%, transparent), 0 0 0 3px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent); }
  .aurora-btn:disabled, .aurora-btn[aria-disabled="true"] { opacity: 0.45; cursor: not-allowed; transform: none; }
  .aurora-btn--block { width: 100%; }
  .aurora-btn--pill { border-radius: 999px; }
  .aurora-btn--sm { height: 27px; padding: 0 11px; border-radius: 7px; font-size: 12px; gap: 6px; }
  .aurora-btn--lg { height: 40px; padding: 0 20px; border-radius: 11px; font-size: 14px; gap: 8px; }
  .aurora-btn--icon { width: 32px; padding: 0; }
  .aurora-btn--sm.aurora-btn--icon { width: 27px; }
  .aurora-btn--lg.aurora-btn--icon { width: 40px; }

  .aurora-btn--aurora {
    border-color: color-mix(in srgb, var(--aurora-accent-primary) 42%, var(--aurora-border-strong));
    background: linear-gradient(180deg, color-mix(in srgb, var(--aurora-accent-primary) 11%, transparent), transparent 58%), var(--aurora-control-surface);
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.055), 0 1px 2px rgba(0,0,0,0.34), 0 2px 6px rgba(0,0,0,0.16), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent);
  }
  .aurora-btn--aurora:hover { border-color: color-mix(in srgb, var(--aurora-accent-primary) 70%, var(--aurora-border-strong)); box-shadow: inset 0 1px 0 rgba(255,255,255,0.08), 0 1px 2px rgba(0,0,0,0.4), 0 3px 9px rgba(0,0,0,0.22), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 38%, transparent); }

  .aurora-btn--neutral:hover { background: var(--aurora-hover-bg); border-color: var(--aurora-border-strong); box-shadow: inset 0 1px 0 rgba(255,255,255,0.07), 0 1px 2px rgba(0,0,0,0.4), 0 3px 9px rgba(0,0,0,0.22); }

  .aurora-btn--rose {
    border-color: color-mix(in srgb, var(--aurora-accent-pink) 52%, var(--aurora-border-strong));
    background: linear-gradient(180deg, color-mix(in srgb, var(--aurora-accent-pink) 14%, transparent), transparent 58%), var(--aurora-control-surface);
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.06), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-pink) 24%, transparent);
  }
  .aurora-btn--rose:hover { border-color: color-mix(in srgb, var(--aurora-accent-pink) 76%, var(--aurora-border-strong)); box-shadow: inset 0 1px 0 rgba(255,255,255,0.08), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-pink) 40%, transparent); }

  .aurora-btn--success {
    color: var(--aurora-success); border-color: color-mix(in srgb, var(--aurora-success) 46%, var(--aurora-border-strong));
    background: linear-gradient(180deg, color-mix(in srgb, var(--aurora-success) 12%, transparent), transparent 58%), var(--aurora-control-surface);
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.05), 0 0 0 1px color-mix(in srgb, var(--aurora-success) 22%, transparent);
  }
  .aurora-btn--success:hover { border-color: color-mix(in srgb, var(--aurora-success) 72%, var(--aurora-border-strong)); box-shadow: inset 0 1px 0 rgba(255,255,255,0.08), 0 0 0 1px color-mix(in srgb, var(--aurora-success) 42%, transparent); }

  .aurora-btn--warn {
    color: var(--aurora-warn); border-color: color-mix(in srgb, var(--aurora-warn) 48%, var(--aurora-border-strong));
    background: linear-gradient(180deg, color-mix(in srgb, var(--aurora-warn) 12%, transparent), transparent 58%), var(--aurora-control-surface);
    box-shadow: inset 0 1px 0 rgba(255,255,255,0.05), 0 0 0 1px color-mix(in srgb, var(--aurora-warn) 22%, transparent);
  }
  .aurora-btn--warn:hover { border-color: color-mix(in srgb, var(--aurora-warn) 74%, var(--aurora-border-strong)); box-shadow: inset 0 1px 0 rgba(255,255,255,0.08), 0 0 0 1px color-mix(in srgb, var(--aurora-warn) 42%, transparent); }

  .aurora-btn--ghost { border-color: transparent; background: transparent; box-shadow: none; color: var(--aurora-text-muted); }
  .aurora-btn--ghost:hover { color: var(--aurora-text-primary); background: var(--aurora-hover-bg); }

  /* plain — structural escape hatch: a bare clickable button with no Aurora fill */
  .aurora-btn--plain { border-color: transparent; background: transparent; box-shadow: none; color: inherit; }
  .aurora-btn--plain:hover { background: transparent; }

  /* unstyled — strip the base dimensions/typography (pairs with --plain for a raw wrapper) */
  .aurora-btn--unstyled { height: auto; min-height: 0; padding: 0; border: 0; border-radius: 0; font-size: inherit; font-weight: inherit; gap: 0; box-shadow: none; }

  /* filled — the one flooded hero action (flooded fills are allowed; keep to one per surface) */
  .aurora-btn--filled.aurora-btn--rose { background: var(--aurora-accent-pink); border-color: var(--aurora-accent-pink-deep); color: #2a0f18; box-shadow: inset 0 1px 0 rgba(255,255,255,0.22), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-pink-deep) 50%, transparent); }
  .aurora-btn--filled.aurora-btn--rose:hover { background: var(--aurora-accent-pink-strong); border-color: var(--aurora-accent-pink-deep); }
  .aurora-btn--filled.aurora-btn--aurora { background: var(--aurora-accent-primary); border-color: var(--aurora-accent-deep); color: #06131c; }
  .aurora-btn--filled.aurora-btn--aurora:hover { background: color-mix(in srgb, var(--aurora-accent-primary) 86%, #fff); }
  .aurora-btn--filled.aurora-btn--success { background: var(--aurora-success); border-color: color-mix(in srgb, var(--aurora-success) 60%, #000); color: #06201b; }
  .aurora-btn--filled.aurora-btn--warn { background: var(--aurora-warn); border-color: color-mix(in srgb, var(--aurora-warn) 60%, #000); color: #211803; }

  .aurora-btn--destructive {
    color: var(--aurora-error); border-color: color-mix(in srgb, var(--aurora-error) 42%, var(--aurora-border-strong));
    background: linear-gradient(180deg, color-mix(in srgb, var(--aurora-error) 9%, transparent), transparent 58%), var(--aurora-control-surface);
  }
  .aurora-btn--destructive:hover { border-color: color-mix(in srgb, var(--aurora-error) 62%, var(--aurora-border-strong)); }

  .aurora-btn--pulse:not(:disabled):not([aria-disabled="true"]) { animation: aurora-btn-pulse 2.4s ease-in-out infinite; }
  .aurora-btn--loading { cursor: progress; }
  .aurora-btn__spinner { width: 1em; height: 1em; border-radius: 50%; border: 2px solid currentColor; border-top-color: transparent; animation: aurora-btn-spin 0.62s linear infinite; flex-shrink: 0; }
  .aurora-btn__icon { display: inline-flex; align-items: center; flex-shrink: 0; }

  @media (prefers-reduced-motion: reduce) {
    .aurora-btn--pulse { animation: none; }
    .aurora-btn__spinner { animation-duration: 1.4s; }
  }

  /* ─── alert-dialog ─── */
.aurora-alert {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: 16px;
  padding: 28px;
  border-radius: var(--aurora-radius-3);
  border: 1px solid color-mix(in srgb, var(--aurora-border-default) 55%, var(--aurora-page-bg));
  background: linear-gradient(180deg, var(--aurora-panel-strong-top), var(--aurora-panel-strong));
  box-shadow: var(--aurora-shadow-strong), var(--aurora-highlight-strong);
  box-sizing: border-box;
}
.aurora-alert__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 44px;
  height: 44px;
  border-radius: 12px;
  border: 1px solid var(--aurora-accent-pink-border);
  background: var(--aurora-accent-pink-surface);
  color: var(--aurora-accent-pink);
  flex-shrink: 0;
}
.aurora-alert--info .aurora-alert__icon {
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 32%, transparent);
  background: color-mix(in srgb, var(--aurora-accent-primary) 12%, var(--aurora-panel-medium));
  color: var(--aurora-accent-primary);
}
.aurora-alert__main { display: flex; flex-direction: column; gap: 8px; min-width: 0; }
.aurora-alert__title {
  margin: 0;
  font-family: var(--font-display, var(--font-sans, Manrope, sans-serif));
  font-weight: 700;
  font-size: 19px;
  line-height: 1.25;
  letter-spacing: -0.01em;
  color: var(--aurora-text-primary);
}
.aurora-alert__desc {
  margin: 0;
  font-family: var(--font-sans, Inter, sans-serif);
  font-size: 15px;
  line-height: 1.5;
  color: var(--aurora-text-muted);
}
.aurora-alert__footer {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 14px;
}

  /* ─── card ─── */
.aurora-card { color: var(--aurora-text-primary); border: 1px solid var(--aurora-border-default); box-sizing: border-box; }
.aurora-card[data-tier="2"] {
  background: linear-gradient(180deg, var(--aurora-panel-strong-top), var(--aurora-panel-strong));
  border-color: color-mix(in srgb, var(--aurora-border-default) 55%, var(--aurora-page-bg));
  border-radius: var(--aurora-radius-3);
  box-shadow: var(--aurora-shadow-strong), var(--aurora-highlight-strong);
}
.aurora-card[data-tier="1"] {
  background: linear-gradient(180deg, var(--aurora-panel-medium-top), var(--aurora-panel-medium));
  border-color: color-mix(in srgb, var(--aurora-border-default) 42%, var(--aurora-page-bg));
  border-radius: var(--aurora-radius-2);
  box-shadow: var(--aurora-shadow-medium), var(--aurora-highlight-medium);
}
.aurora-card[data-accent="cyan"] {
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 60%, var(--aurora-border-default));
  box-shadow: var(--aurora-shadow-strong), var(--aurora-highlight-strong), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent), 0 0 20px color-mix(in srgb, var(--aurora-accent-primary) 12%, transparent);
}
.aurora-card[data-accent="rose"] {
  border-color: color-mix(in srgb, var(--aurora-accent-pink) 60%, var(--aurora-border-default));
  box-shadow: var(--aurora-shadow-strong), var(--aurora-highlight-strong), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-pink) 22%, transparent), 0 0 20px color-mix(in srgb, var(--aurora-accent-pink) 12%, transparent);
}
.aurora-card[data-interactive="true"] {
  cursor: pointer;
  transition: transform 160ms var(--motion-ease-out, ease), box-shadow 160ms var(--motion-ease-out, ease), border-color 160ms var(--motion-ease-out, ease);
}
.aurora-card[data-interactive="true"]:hover {
  transform: translateY(-2px);
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 38%, var(--aurora-border-strong));
  box-shadow: var(--aurora-shadow-strong), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 30%, transparent);
}
.aurora-card[data-interactive="true"]:focus-visible {
  outline: none;
  box-shadow: var(--aurora-shadow-strong), 0 0 0 3px var(--aurora-focus-ring);
}
@media (prefers-reduced-motion: reduce) { .aurora-card[data-interactive="true"] { transition: none; } }

  /* ─── carousel ─── */
.aurora-carousel { display: grid; gap: 14px; }
.aurora-carousel__head { display: flex; align-items: center; justify-content: space-between; gap: 12px; }
.aurora-carousel__title {
  margin: 0;
  font-family: var(--aurora-font-display);
  font-weight: 800;
  font-size: 26px;
  line-height: 1.1;
  letter-spacing: -0.02em;
  color: var(--aurora-text-primary);
}
.aurora-carousel__controls { display: flex; gap: 8px; }
.aurora-carousel__track {
  display: flex;
  gap: 12px;
  overflow-x: auto;
  scroll-snap-type: x mandatory;
  padding-bottom: 4px;
  scrollbar-width: thin;
}
.aurora-carousel__slide { min-width: 240px; scroll-snap-align: start; }
.aurora-carousel__item {
  position: relative;
  border-radius: 8px;
  border: 1px solid var(--aurora-border-default);
  background:
    linear-gradient(180deg, var(--aurora-panel-medium-top), transparent 60%),
    var(--aurora-panel-medium);
  box-shadow: var(--aurora-shadow-medium), var(--aurora-highlight-medium);
  padding: 16px;
}

  /* ─── chat-message ─── */
.aurora-chat-message {
  display: flex;
  flex-direction: column;
  font-family: var(--font-sans);
  color: var(--aurora-text-primary);
}
.aurora-chat-message[data-role="user"] {
  align-items: flex-end;
}
.aurora-chat-message[data-role="assistant"] {
  align-items: flex-start;
}

/* Assistant header row: avatar + author + time */
.aurora-chat-message__head {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 10px;
}
.aurora-chat-message__avatar {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  flex: 0 0 auto;
  border-radius: var(--radius-1, 14px);
  background: var(--aurora-panel-strong);
  border: 1px solid var(--aurora-border-default);
  color: var(--aurora-accent-pink);
}
.aurora-chat-message__meta {
  display: flex;
  align-items: baseline;
  gap: 8px;
  min-width: 0;
}
.aurora-chat-message__author {
  font-family: var(--font-sans);
  font-size: 15px;
  font-weight: 700;
  line-height: 1.2;
  color: var(--aurora-text-primary);
}
.aurora-chat-message__time {
  font-family: var(--font-sans);
  font-size: 13px;
  font-weight: 500;
  line-height: 1.2;
  color: var(--aurora-text-muted);
}

/* Bubble */
.aurora-chat-message__bubble {
  position: relative;
  max-width: 100%;
  padding: 16px 20px;
  border-radius: var(--radius-2, 18px);
  font-size: 17px;
  line-height: 1.5;
  border: 1px solid transparent;
  box-sizing: border-box;
}
.aurora-chat-message[data-role="user"] .aurora-chat-message__bubble {
  background: color-mix(in srgb, var(--aurora-accent-primary) 12%, transparent);
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 42%, transparent);
  color: var(--aurora-text-primary);
  text-align: right;
}
.aurora-chat-message[data-role="assistant"] .aurora-chat-message__bubble {
  background: var(--aurora-panel-medium);
  border-color: var(--aurora-border-default);
  color: var(--aurora-text-primary);
  text-align: left;
}
.aurora-chat-message__bubble p {
  margin: 0;
}
.aurora-chat-message__bubble p + p {
  margin-top: 12px;
}

/* Inline code chips */
.aurora-chat-message__bubble code {
  font-family: var(--font-mono);
  font-size: 0.9em;
  padding: 2px 7px;
  border-radius: 7px;
  background: color-mix(in srgb, var(--aurora-accent-pink) 12%, var(--aurora-panel-medium));
  color: var(--aurora-accent-pink);
}

/* Citations — sit below the bubble, aligned to the message column */
.aurora-chat-message__citations {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-top: 10px;
}
.aurora-chat-message[data-role="user"] .aurora-chat-message__citations {
  justify-content: flex-end;
}
.aurora-chat-message__citation {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  padding: 6px 12px;
  border-radius: var(--radius-1, 14px);
  border: 1px solid var(--aurora-border-default);
  background: var(--aurora-control-surface);
  font-family: var(--font-mono);
  font-size: 13px;
  font-weight: 500;
  line-height: 1;
  color: var(--aurora-text-muted);
  text-decoration: none;
  transition: border-color 120ms ease, color 120ms ease;
}
.aurora-chat-message__citation:hover {
  border-color: var(--aurora-border-strong);
  color: var(--aurora-text-primary);
}
.aurora-chat-message__citation-icon {
  color: var(--aurora-accent-pink);
  flex: 0 0 auto;
}

  /* ─── chat-sidebar ─── */
.aurora-chat-sidebar {
  display: flex;
  flex-direction: column;
  height: 100%;
  width: 100%;
  box-sizing: border-box;
  font-family: var(--font-sans);
  color: var(--aurora-text-primary);
  background: var(--aurora-page-bg);
  border-right: 1px solid var(--aurora-border-default);
}

/* Brand row */
.aurora-chat-sidebar__brand {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 18px 18px 14px;
  font-family: var(--font-sans);
  font-size: 20px;
  font-weight: 800;
  line-height: 1.1;
  letter-spacing: -0.01em;
  color: var(--aurora-text-primary);
}
.aurora-chat-sidebar__brand svg {
  flex: 0 0 auto;
}

/* New chat + search live in a padded header block */
.aurora-chat-sidebar__head {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 0 18px 14px;
}

/* New chat button */
.aurora-chat-sidebar__new {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  width: 100%;
  padding: 14px 16px;
  border-radius: var(--radius-1, 14px);
  border: 1px solid color-mix(in srgb, var(--aurora-accent-primary) 42%, transparent);
  background: linear-gradient(
    180deg,
    color-mix(in srgb, var(--aurora-accent-primary) 16%, var(--aurora-panel-strong)) 0%,
    var(--aurora-panel-strong) 100%
  );
  color: var(--aurora-text-primary);
  font-family: var(--font-sans);
  font-size: 16px;
  font-weight: 600;
  line-height: 1;
  cursor: pointer;
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 18%, transparent),
    0 8px 18px color-mix(in srgb, var(--aurora-accent-primary) 14%, transparent);
  transition: border-color 120ms ease, box-shadow 120ms ease, background 120ms ease;
}
.aurora-chat-sidebar__new:hover {
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 60%, transparent);
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 28%, transparent),
    0 10px 22px color-mix(in srgb, var(--aurora-accent-primary) 20%, transparent);
}
.aurora-chat-sidebar__new:focus-visible {
  outline: none;
  border-color: var(--aurora-accent-strong);
  box-shadow: 0 0 0 3px var(--aurora-focus-ring-strong);
}
.aurora-chat-sidebar__new-icon {
  flex: 0 0 auto;
  color: var(--aurora-text-primary);
}

/* Search field */
.aurora-chat-sidebar__search {
  position: relative;
  display: flex;
  align-items: center;
}
.aurora-chat-sidebar__search-icon {
  position: absolute;
  left: 16px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--aurora-text-muted);
  pointer-events: none;
}
.aurora-chat-sidebar__search-input {
  width: 100%;
  box-sizing: border-box;
  padding: 12px 14px 12px 44px;
  border-radius: var(--radius-1, 14px);
  border: 1px solid var(--aurora-border-default);
  background: var(--aurora-control-surface);
  color: var(--aurora-text-primary);
  font-family: var(--font-sans);
  font-size: 15px;
  line-height: 1.2;
  transition: border-color 120ms ease, box-shadow 120ms ease;
}
.aurora-chat-sidebar__search-input::placeholder {
  color: var(--aurora-text-muted);
}
.aurora-chat-sidebar__search-input:focus-visible {
  outline: none;
  border-color: var(--aurora-accent-strong);
  box-shadow: 0 0 0 3px var(--aurora-focus-ring-strong);
}

/* Thread list */
.aurora-chat-sidebar__threads {
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
  padding: 4px 12px 12px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.aurora-chat-sidebar__bucket {
  padding: 14px 8px 6px;
  font-family: var(--font-sans);
  font-size: 12px;
  font-weight: 700;
  line-height: 1;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--aurora-text-muted);
}
.aurora-chat-sidebar__thread {
  display: flex;
  align-items: center;
  gap: 12px;
  width: 100%;
  box-sizing: border-box;
  padding: 11px 12px;
  border-radius: var(--radius-1, 14px);
  border: 1px solid transparent;
  background: transparent;
  color: var(--aurora-text-muted);
  font-family: var(--font-sans);
  font-size: 16px;
  font-weight: 500;
  line-height: 1.25;
  text-align: left;
  cursor: pointer;
  transition: background 120ms ease, color 120ms ease, border-color 120ms ease;
}
.aurora-chat-sidebar__thread:hover {
  background: var(--aurora-panel-medium);
  color: var(--aurora-text-primary);
}
.aurora-chat-sidebar__thread:focus-visible {
  outline: none;
  border-color: var(--aurora-accent-strong);
