}
.aurora-chat-sidebar__thread[data-active="true"] {
  background: color-mix(in srgb, var(--aurora-accent-primary) 12%, var(--aurora-panel-medium));
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 48%, transparent);
