}
.aurora-chat-sidebar__thread[data-active="false"] .aurora-chat-sidebar__thread-icon {
  color: var(--aurora-text-muted);
}
.aurora-chat-sidebar__thread-title {
  flex: 1 1 auto;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* User footer */
.aurora-chat-sidebar__footer {
  display: flex;
  align-items: center;
  gap: 12px;
  flex: 0 0 auto;
  padding: 12px 16px;
