}
.aurora-chat-sidebar__avatar {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex: 0 0 auto;
  width: 40px;
  height: 40px;
  border-radius: var(--radius-pill, 999px);
  border: 1px solid color-mix(in srgb, var(--aurora-accent-primary) 48%, transparent);
  background: color-mix(in srgb, var(--aurora-accent-primary) 14%, var(--aurora-panel-medium));
  color: var(--aurora-accent-strong);
  font-family: var(--font-sans);
  font-size: 13px;
  font-weight: 700;
  line-height: 1;
  letter-spacing: 0.02em;
}
.aurora-chat-sidebar__user {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
  flex: 1 1 auto;
}
.aurora-chat-sidebar__user-name {
  font-family: var(--font-sans);
  font-size: 15px;
  font-weight: 700;
  line-height: 1.2;
  color: var(--aurora-text-primary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.aurora-chat-sidebar__user-plan {
  font-family: var(--font-sans);
  font-size: 13px;
  font-weight: 500;
  line-height: 1.2;
  color: var(--aurora-text-muted);
}
.aurora-chat-sidebar__menu {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex: 0 0 auto;
  width: 28px;
  height: 28px;
  padding: 0;
  border-radius: var(--radius-1, 14px);
  border: 1px solid transparent;
  background: transparent;
  color: var(--aurora-text-muted);
  cursor: pointer;
  transition: background 120ms ease, color 120ms ease, border-color 120ms ease;
}
.aurora-chat-sidebar__menu:hover {
  background: var(--aurora-panel-medium);
  color: var(--aurora-text-primary);
}
.aurora-chat-sidebar__menu:focus-visible {
  outline: none;
  border-color: var(--aurora-accent-strong);
  box-shadow: 0 0 0 3px var(--aurora-focus-ring-strong);
}

  /* ─── checkbox ─── */
.aurora-checkbox {
  display: inline-grid; place-items: center; flex-shrink: 0; cursor: pointer;
  width: 19px; height: 19px; border-radius: 5px; padding: 0;
  background: var(--aurora-control-surface); border: 1px solid var(--aurora-border-strong);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.04);
  transition: background 140ms ease, border-color 140ms ease, box-shadow 140ms ease;
  position: relative;
}
.aurora-checkbox:hover {
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 40%, var(--aurora-border-strong));
}
.aurora-checkbox:focus-visible {
  outline: none;
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent);
}
.aurora-checkbox[data-state="checked"],
.aurora-checkbox[data-state="indeterminate"] {
  background: color-mix(in srgb, var(--aurora-accent-primary) 30%, var(--aurora-control-surface));
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 60%, var(--aurora-border-strong));
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent);
}
.aurora-checkbox:disabled { opacity: 0.45; cursor: not-allowed; }
.aurora-checkbox svg {
  color: var(--aurora-accent-strong); opacity: 0;
  transition: opacity 120ms ease;
  position: absolute;
}
.aurora-checkbox[data-state="checked"] svg.aurora-checkbox__check { opacity: 1; }
.aurora-checkbox[data-state="indeterminate"] svg.aurora-checkbox__dash { opacity: 1; }

  /* ─── copy-button ─── */
.aurora-copy-btn {
  position: relative; display: inline-flex; align-items: center; justify-content: center; gap: 7px;
  white-space: nowrap; cursor: pointer; user-select: none; font-family: var(--font-sans, Inter, sans-serif);
  font-weight: 560; border: 1px solid var(--aurora-border-strong); background: var(--aurora-control-surface);
  color: var(--aurora-text-primary); height: 32px; padding: 0 14px; border-radius: 9px; font-size: 13px;
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.05), 0 1px 2px rgba(0,0,0,0.34), 0 2px 6px rgba(0,0,0,0.16);
  text-decoration: none; box-sizing: border-box;
  transition: background 150ms var(--motion-ease-out, ease), border-color 150ms var(--motion-ease-out, ease), box-shadow 200ms var(--motion-ease-out, ease), color 150ms var(--motion-ease-out, ease), transform 80ms ease-out;
}
.aurora-copy-btn:hover { background: var(--aurora-hover-bg); border-color: var(--aurora-border-strong); box-shadow: inset 0 1px 0 rgba(255,255,255,0.07), 0 1px 2px rgba(0,0,0,0.4), 0 3px 9px rgba(0,0,0,0.22); }
.aurora-copy-btn:active { transform: translateY(1px); }
.aurora-copy-btn:focus-visible { outline: none; box-shadow: inset 0 1px 0 rgba(255,255,255,0.055), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 45%, transparent), 0 0 0 3px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent); }
.aurora-copy-btn:disabled, .aurora-copy-btn[aria-disabled="true"] { opacity: 0.45; cursor: not-allowed; transform: none; }

/* icon-only square when there is no label */
.aurora-copy-btn--icon { width: 32px; padding: 0; }

/* copied state — brief success glow */
.aurora-copy-btn--copied {
  color: var(--aurora-success);
  border-color: color-mix(in srgb, var(--aurora-success) 46%, var(--aurora-border-strong));
  background: linear-gradient(180deg, color-mix(in srgb, var(--aurora-success) 12%, transparent), transparent 58%), var(--aurora-control-surface);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.05), 0 0 0 1px color-mix(in srgb, var(--aurora-success) 22%, transparent);
}
.aurora-copy-btn--copied:hover {
  border-color: color-mix(in srgb, var(--aurora-success) 72%, var(--aurora-border-strong));
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.08), 0 0 0 1px color-mix(in srgb, var(--aurora-success) 42%, transparent);
}

.aurora-copy-btn__icon { display: inline-flex; align-items: center; flex-shrink: 0; }
.aurora-copy-btn__icon svg { display: block; }

  /* ─── number-input ─── */
.aurora-number-input {
  display: inline-grid;
  grid-template-columns: 32px minmax(0, 1fr) 32px;
  align-items: center;
  gap: 8px;
  width: 100%;
}
/* Center field — lit accent ring, pill rounding, centered value (CD spec). */
.aurora-number-input__field {
  width: 100%;
  height: 32px;
  padding: 0 12px;
  text-align: center;
  border-radius: 999px;
  border: 1px solid color-mix(in srgb, var(--aurora-accent-primary) 38%, var(--aurora-border-strong));
  background: var(--aurora-control-surface);
  color: var(--aurora-text-primary);
  font-family: var(--font-sans, Inter, sans-serif);
  font-size: 13px;
  font-weight: 560;
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.04),
    0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 18%, transparent);
  box-sizing: border-box;
  appearance: textfield;
  -moz-appearance: textfield;
  transition:
    border-color 150ms var(--motion-ease-out, ease),
    box-shadow 200ms var(--motion-ease-out, ease);
}
.aurora-number-input__field::-webkit-outer-spin-button,
.aurora-number-input__field::-webkit-inner-spin-button {
  appearance: none;
  -webkit-appearance: none;
  margin: 0;
}
.aurora-number-input__field:focus,
.aurora-number-input__field:focus-visible {
  outline: none;
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 60%, var(--aurora-border-strong));
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.055),
    0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 45%, transparent),
    0 0 0 3px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent);
}
.aurora-number-input__field:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

  /* ─── operation-icon ─── */
.aurora-op-icon {
  display: inline-flex; align-items: center; justify-content: center; flex-shrink: 0;
  border-radius: 8px; box-sizing: border-box;
  background: var(--aurora-op-surface);
  border: 1px solid var(--aurora-op-border);
  color: var(--aurora-op-fg);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.04);
}
.aurora-op-icon svg { display: block; }

/* cyan — fetch / read */
.aurora-op-icon--cyan {
  --aurora-op-fg: var(--aurora-accent-strong);
  --aurora-op-surface: color-mix(in srgb, var(--aurora-accent-primary) 13%, var(--aurora-control-surface));
  --aurora-op-border: color-mix(in srgb, var(--aurora-accent-primary) 34%, transparent);
}
/* orange — async jobs */
.aurora-op-icon--orange {
  --aurora-op-fg: var(--axon-orange-strong);
  --aurora-op-surface: color-mix(in srgb, var(--axon-orange) 14%, var(--aurora-control-surface));
  --aurora-op-border: color-mix(in srgb, var(--axon-orange) 36%, transparent);
}
/* rose — reason */
.aurora-op-icon--rose {
  --aurora-op-fg: var(--aurora-accent-pink-strong);
  --aurora-op-surface: color-mix(in srgb, var(--aurora-accent-pink) 13%, var(--aurora-control-surface));
  --aurora-op-border: color-mix(in srgb, var(--aurora-accent-pink) 34%, transparent);
}
/* neutral — fallback */
.aurora-op-icon--neutral {
  --aurora-op-fg: var(--aurora-text-muted);
  --aurora-op-surface: color-mix(in srgb, var(--aurora-text-muted) 8%, var(--aurora-control-surface));
  --aurora-op-border: color-mix(in srgb, var(--aurora-border-default) 70%, transparent);
}

  /* ─── skeleton ─── */
    .aurora-shimmer {
      background: linear-gradient(
        90deg,
        var(--aurora-panel-strong) 25%,
        color-mix(in srgb, var(--aurora-border-strong) 60%, transparent) 37%,
        var(--aurora-panel-strong) 63%
      );
      background-size: 800px 100%;
      animation: aurora-shimmer 1.4s ease-in-out infinite;
    }

  /* ─── status-dot ─── */
    .aurora-status-dot {
      position: relative;
      flex: none;
      width: 9px;
      height: 9px;
      border-radius: 9999px;
      background: var(--status-dot-color);
      box-shadow:
        0 0 0 0 color-mix(in srgb, var(--status-dot-color) 36%, transparent),
        0 0 6px color-mix(in srgb, var(--status-dot-color) 70%, transparent);
    }
    .aurora-status-dot--pulse {
      animation: aurora-status-dot-pulse 1.8s var(--motion-ease-in-out, ease-in-out) infinite;
    }
    @media (prefers-reduced-motion: reduce) {
      .aurora-status-dot--pulse {
        animation: none;
      }
    }

  /* ─── stepper ─── */
.aurora-stepper {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  gap: 0;
  margin: 0;
  padding: 0;
  list-style: none;
  font-family: var(--font-sans, "Inter", system-ui, sans-serif);
}
.aurora-stepper__step {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 12px;
  min-width: 96px;
}
.aurora-stepper__node {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  border-radius: 9999px;
  border: 2px solid transparent;
  font-family: var(--font-sans, "Inter", system-ui, sans-serif);
  font-size: 16px;
  font-weight: 700;
  line-height: 1;
  box-sizing: border-box;
  transition:
    background-color var(--motion-fast, 140ms) ease,
    border-color var(--motion-fast, 140ms) ease,
    color var(--motion-fast, 140ms) ease;
}
.aurora-stepper__step[data-status="complete"] .aurora-stepper__node {
  background: var(--aurora-accent-primary);
  border-color: var(--aurora-accent-primary);
  color: var(--aurora-accent-foreground);
}
.aurora-stepper__step[data-status="active"] .aurora-stepper__node {
  background: color-mix(in srgb, var(--aurora-accent-primary) 18%, transparent);
  border-color: var(--aurora-accent-primary);
  color: var(--aurora-accent-primary);
}
.aurora-stepper__step[data-status="upcoming"] .aurora-stepper__node {
  background: transparent;
  border-color: var(--aurora-border-default);
  color: var(--aurora-text-muted);
}
.aurora-stepper__check {
  width: 20px;
  height: 20px;
}
.aurora-stepper__text {
  display: block;
  text-align: center;
}
.aurora-stepper__label {
  display: block;
  font-size: 14px;
  font-weight: 700;
  line-height: 1.2;
  text-align: center;
}
.aurora-stepper__step[data-status="upcoming"] .aurora-stepper__label {
  color: var(--aurora-text-muted);
  font-weight: 600;
}
.aurora-stepper__step[data-status="complete"] .aurora-stepper__label,
.aurora-stepper__step[data-status="active"] .aurora-stepper__label {
  color: var(--aurora-text-primary);
}
.aurora-stepper__description {
  margin-top: 4px;
  font-size: 12px;
  font-weight: 500;
  line-height: 1.3;
  text-align: center;
  color: var(--aurora-text-muted);
}

  /* ─── switch ─── */
[data-aurora-switch] {
  background: var(--aurora-control-surface);
  border: 1px solid var(--aurora-border-strong);
  transition: background 160ms var(--motion-ease-out, ease), border-color 160ms var(--motion-ease-out, ease), box-shadow 160ms var(--motion-ease-out, ease);
}
[data-aurora-switch]:focus-visible {
  outline: none;
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent);
}
[data-aurora-switch][data-state="checked"] {
  background: color-mix(in srgb, var(--aurora-accent-primary) 32%, var(--aurora-control-surface));
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 50%, var(--aurora-border-strong));
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent);
}
[data-aurora-switch]:disabled { opacity: 0.45; cursor: not-allowed; }

[data-aurora-switch] [data-radix-switch-thumb] {
  background: var(--aurora-text-muted);
  transition: transform 160ms var(--motion-ease-out, ease), background 160ms var(--motion-ease-out, ease), box-shadow 160ms var(--motion-ease-out, ease);
  pointer-events: none;
}
[data-aurora-switch][data-state="checked"] [data-radix-switch-thumb] {
  background: var(--aurora-accent-strong);
  box-shadow: 0 0 8px var(--aurora-accent-primary);
}

[data-aurora-switch="sm"]      [data-radix-switch-thumb]                       { transform: translateX(2px);  }
[data-aurora-switch="sm"][data-state="checked"]      [data-radix-switch-thumb] { transform: translateX(16px); }
[data-aurora-switch="default"] [data-radix-switch-thumb]                       { transform: translateX(2px);  }
[data-aurora-switch="default"][data-state="checked"] [data-radix-switch-thumb] { transform: translateX(19px); }
[data-aurora-switch="lg"]      [data-radix-switch-thumb]                       { transform: translateX(3px);  }
[data-aurora-switch="lg"][data-state="checked"]      [data-radix-switch-thumb] { transform: translateX(23px); }

@media (prefers-reduced-motion: reduce) {
  [data-aurora-switch], [data-aurora-switch] [data-radix-switch-thumb] { transition: none; }
}

  /* ─── toast ─── */
    .aurora-toast-enter { animation: toast-slide-in  0.28s cubic-bezier(0.16,1,0.3,1) forwards; }
    .aurora-toast-exit  { animation: aurora-toast-out 0.22s ease-in             forwards; }

  /* ─── color-picker ─── */
.aurora-cp {
  width: 100%;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding: 20px;
  border-radius: var(--radius-3, 16px);
  background: var(--aurora-panel-strong);
  border: 1px solid var(--aurora-border-default);
  font-family: var(--font-sans, "Inter", system-ui, sans-serif);
  color: var(--aurora-text-primary);
}
.aurora-cp *,
.aurora-cp *::before,
.aurora-cp *::after { box-sizing: border-box; }
.aurora-cp__label {
  font-family: var(--font-sans, "Inter", system-ui, sans-serif);
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--aurora-text-muted);
  margin: 0;
}
.aurora-cp__sv {
  position: relative;
  width: 100%;
  height: 160px;
  border-radius: var(--radius-2, 12px);
  border: 1px solid var(--aurora-border-default);
  cursor: crosshair;
  touch-action: none;
  overflow: hidden;
  outline: none;
}
.aurora-cp__sv:focus-visible {
  box-shadow: 0 0 0 2px color-mix(in srgb, var(--aurora-accent-primary) 60%, transparent);
}
.aurora-cp__sv-handle {
  position: absolute;
  width: 18px;
  height: 18px;
  border-radius: 999px;
  border: 2px solid #ffffff;
  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.45), 0 1px 4px rgba(0, 0, 0, 0.5);
  transform: translate(-50%, -50%);
  pointer-events: none;
}
.aurora-cp__hue {
  position: relative;
  width: 100%;
  height: 14px;
  border-radius: 999px;
  cursor: pointer;
  touch-action: none;
  outline: none;
  background: linear-gradient(
    90deg,
    #ff0000 0%,
    #ffff00 17%,
    #00ff00 33%,
    #00ffff 50%,
    #0000ff 67%,
    #ff00ff 83%,
    #ff0000 100%
  );
  border: 1px solid var(--aurora-border-strong);
}
.aurora-cp__hue:focus-visible {
  box-shadow: 0 0 0 2px color-mix(in srgb, var(--aurora-accent-primary) 60%, transparent);
}
.aurora-cp__hue-handle {
  position: absolute;
  top: 50%;
  width: 16px;
  height: 16px;
  border-radius: 999px;
  border: 2px solid #ffffff;
  background: var(--aurora-cp-color, #29b6f6);
  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.45), 0 1px 4px rgba(0, 0, 0, 0.5);
  transform: translate(-50%, -50%);
  pointer-events: none;
}
.aurora-cp__row {
  display: flex;
  align-items: stretch;
  gap: 12px;
}
.aurora-cp__preview {
  flex: none;
  width: 64px;
  height: 56px;
  border-radius: var(--radius-2, 12px);
  background: var(--aurora-cp-color, #29b6f6);
  border: 1px solid color-mix(in srgb, #ffffff 16%, transparent);
}
.aurora-cp__input-wrap {
  flex: 1 1 auto;
  display: flex;
  align-items: center;
  gap: 8px;
  height: 56px;
  padding: 0 14px;
  border-radius: var(--radius-2, 12px);
  background: var(--aurora-control-surface);
  border: 1px solid var(--aurora-border-strong);
  transition: border-color 120ms var(--aurora-motion-ease, ease),
    box-shadow 120ms var(--aurora-motion-ease, ease);
}
.aurora-cp__input-wrap:focus-within {
  border-color: color-mix(in srgb, var(--aurora-accent-primary) 70%, var(--aurora-border-strong));
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 40%, transparent);
}
.aurora-cp__hash {
  font-family: var(--font-mono, "JetBrains Mono", monospace);
  font-size: 16px;
  font-weight: 600;
  color: var(--aurora-text-muted);
  user-select: none;
}
.aurora-cp__input {
  flex: 1 1 auto;
  min-width: 0;
  background: transparent;
  border: none;
  outline: none;
  color: var(--aurora-text-primary);
  font-family: var(--font-mono, "JetBrains Mono", monospace);
  font-size: 16px;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  padding: 0;
}
.aurora-cp__swatches {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}
.aurora-cp__swatch {
  width: 44px;
  height: 44px;
  flex: none;
  border-radius: var(--radius-2, 12px);
  background: var(--aurora-cp-swatch, #29b6f6);
  border: 1px solid color-mix(in srgb, #ffffff 14%, transparent);
  cursor: pointer;
  padding: 0;
  outline: none;
  transition: transform 120ms var(--aurora-motion-ease, ease),
    box-shadow 120ms var(--aurora-motion-ease, ease);
}
.aurora-cp__swatch:hover {
  transform: translateY(-1px);
}
.aurora-cp__swatch:focus-visible {
  box-shadow: 0 0 0 2px color-mix(in srgb, var(--aurora-accent-primary) 60%, transparent);
}
.aurora-cp__swatch[data-selected="true"] {
  box-shadow:
    0 0 0 2px var(--aurora-panel-strong),
    0 0 0 4px var(--aurora-accent-primary);
}

  /* ─── drawer ─── */
.aurora-drawer-overlay {
  position: fixed;
  inset: 0;
  z-index: 50;
  background: var(--aurora-overlay);
}
