  width: 16px;
  height: 16px;
  margin-top: -6px;
  border-radius: 999px;
  background: var(--aurora-slider-tone);
  border: 2px solid var(--aurora-panel-strong);
  box-shadow:
    0 0 0 1px color-mix(in srgb, var(--aurora-slider-tone) 45%, transparent),
