/* pressed / toggled */
.aurora-action[data-pressed="true"] {
  color: var(--aurora-text-primary);
  border-color: color-mix(
    in srgb,
    var(--aurora-accent-primary) 38%,
    var(--aurora-border-strong)
  );
  background: color-mix(
    in srgb,
    var(--aurora-accent-primary) 12%,
    var(--aurora-panel-strong)
  );
}
.aurora-action:focus-visible {
  outline: none;
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.05),
    0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 45%, transparent),
    0 0 0 3px color-mix(in srgb, var(--aurora-accent-primary) 22%, transparent);
}
.aurora-action:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
}

/* Global keyframes (deduped; layers don't meaningfully scope @keyframes). */
/* Keyframes stay global (layers don't meaningfully scope @keyframes). */
@keyframes aurora-btn-pulse {
  0%, 100% { box-shadow: inset 0 1px 0 rgba(255,255,255,0.055), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 30%, transparent); }
  50% { box-shadow: inset 0 1px 0 rgba(255,255,255,0.055), 0 0 0 1px color-mix(in srgb, var(--aurora-accent-primary) 60%, transparent); }
}

@keyframes aurora-btn-spin { to { transform: rotate(360deg); } }

@keyframes aurora-beacon-ping {
  0%   { transform: scale(1);    opacity: 0.6; }
  70%  { transform: scale(1.55); opacity: 0;   }
  100% { transform: scale(1.55); opacity: 0;   }
}

@keyframes aurora-beacon-ring {
  0%, 100% { opacity: 0.7; }
  50%       { opacity: 1;   }
}

@keyframes aurora-progress-shimmer {
  0%   { transform: translateX(-100%); }
  100% { transform: translateX(400%); }
}

@keyframes aurora-progress-indeterminate {
  0%   { left: -35%; right: 100%; }
  60%  { left: 100%; right: -90%; }
  100% { left: 100%; right: -90%; }
}

@keyframes aurora-shimmer {
      0%   { background-position: -800px 0; }
      100% { background-position:  800px 0; }
    }

@keyframes aurora-status-dot-pulse {
      0%, 100% {
        box-shadow:
          0 0 0 0 color-mix(in srgb, var(--status-dot-color) 42%, transparent),
          0 0 6px color-mix(in srgb, var(--status-dot-color) 70%, transparent);
      }
      50% {
        box-shadow:
          0 0 0 5px transparent,
          0 0 9px color-mix(in srgb, var(--status-dot-color) 85%, transparent);
      }
    }

@keyframes toast-slide-in {
      from { transform: translateX(28px); opacity: 0; }
      to   { transform: translateX(0);    opacity: 1; }
    }

@keyframes aurora-toast-out {
      from { transform: translateX(0);    opacity: 1; max-height: 120px; margin-bottom: 10px; }
      to   { transform: translateX(28px); opacity: 0; max-height: 0;    margin-bottom: 0; }
    }

@keyframes aurora-drawer-overlay-in { from { opacity: 0 } to { opacity: 1 } }

@keyframes aurora-drawer-overlay-out { from { opacity: 1 } to { opacity: 0 } }

@keyframes aurora-drawer-in { from { transform: translateY(100%) } to { transform: translateY(0) } }

@keyframes aurora-drawer-out { from { transform: translateY(0) } to { transform: translateY(100%) } }

@keyframes aurora-blink-cursor {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0; }
}

@keyframes aurora-spin {
  to { transform: rotate(360deg); }
}

@keyframes aurora-auq-fadein {
  from { opacity: 0; transform: translateY(4px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes aurora-cot-spin { to { transform: rotate(360deg); } }

@keyframes aurora-cot-blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }

@keyframes aurora-cot-pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.55; } }

@keyframes aurora-connection-flow {
  to { background-position: 12px 0; }
}

@keyframes aurora-edge-flow {
  to { background-position: 0 0, 12px 0; }
}

@keyframes aurora-loader-spin {
  to { transform: rotate(360deg); }
}

@keyframes aurora-loader-dot {
  0%, 80%, 100% { opacity: 0.25; transform: scale(0.7); }
  40%           { opacity: 1;    transform: scale(1); }
}

@keyframes aurora-loader-bar {
  0%, 100% { transform: scaleY(0.35); }
  50%      { transform: scaleY(1); }
}

@keyframes aurora-loader-pulse-ring {
  0%   { transform: scale(0.45); opacity: 0.9; }
  100% { transform: scale(1);    opacity: 0; }
}

@keyframes aurora-loader-pulse-core {
  0%, 100% { opacity: 1;    transform: scale(1); }
  50%      { opacity: 0.55; transform: scale(0.82); }
}

@keyframes aurora-msg-caret {
  0%, 45%  { opacity: 1; }
  55%, 100% { opacity: 0; }
}

@keyframes aurora-mic-pulse {
  0%, 100% { transform: scaleY(0.55); opacity: 0.7; }
  50% { transform: scaleY(1); opacity: 1; }
}

@keyframes aurora-plan-spin { to { transform: rotate(360deg); } }

@keyframes aurora-plan-blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }

@keyframes aurora-reasoning-blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0; }
  }

@keyframes aurora-response-fade-in {
  from { opacity: 0; transform: translateY(2px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes aurora-response-caret {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

@keyframes aurora-speech-meter {
    0%, 100% { transform: scaleY(0.42); }
    50%      { transform: scaleY(1); }
  }

@keyframes aurora-speech-dot {
    0%, 100% { opacity: 1; transform: scale(1); }
    50%      { opacity: 0.45; transform: scale(0.82); }
  }

@keyframes aurora-tool-spin { to { transform: rotate(360deg); } }

@keyframes aurora-border-pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.4; }
  }

@keyframes aurora-blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0; }
  }

@keyframes aurora-thinking-shimmer {
    0% { background-position: 200% 0; }
    100% { background-position: -200% 0; }
  }

@keyframes aurora-check-pop {
  0% { transform: scale(0.5); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes aurora-check-draw {
  from { stroke-dashoffset: 30; }
  to   { stroke-dashoffset: 0; }
}

@keyframes aurora-pd-in {
  from { opacity: 0; transform: translateY(-6px) scale(0.97); }
  to   { opacity: 1; transform: translateY(0) scale(1); }
}

@keyframes aurora-bar-bounce {
  0%, 100% { transform: scaleY(0.35); }
  50%       { transform: scaleY(1); }
}

@keyframes aurora-error-squiggle {}

@keyframes aurora-fp-in {
  from { opacity: 0; transform: translate(-50%, calc(-50% - 12px)); }
  to   { opacity: 1; transform: translate(-50%, -50%); }
}

@keyframes aurora-cursor-blink {
          0%, 100% { opacity: 0.7; }
          50% { opacity: 0; }
        }

@keyframes aurora-cmd-in {
  from { opacity: 0; transform: translate(-50%, calc(-50% - 8px)); }
  to   { opacity: 1; transform: translate(-50%, -50%); }
}

@keyframes aurora-backdrop-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes aurora-share-in {
  from { opacity: 0; transform: translate(-50%, calc(-50% - 10px)); }
  to   { opacity: 1; transform: translate(-50%, -50%); }
}

@keyframes aurora-shimmer-web {
  0%   { background-position: -400px 0; }
  100% { background-position:  400px 0; }
}

@keyframes aurora-context-shimmer{0%{transform:translateX(-100%)}100%{transform:translateX(100%)}}
